cons class name (e.g., dashicons-no, dashicons-dismiss). '=>'Tẹ orúkọ kilasi Dashicons kan (àpẹẹrẹ, dashicons-no, dashicons-dismiss). ','Reset All Custom Labels'=>'Tun gbogbo Àkọlé Àdáni ṣe','This will reset all renamed checklist items back to their default labels.'=>'Èyí yóò tún gbogbo ohun àtòkọ tí a ti yí orúkọ wọn padà sí àkọlé àtọkànwá wọn.','Security check failed.'=>'Ìdánwò ààbò kọ́ ṣẹ́gun.','You do not have permission to perform this action.'=>'Ìwọ kò ní ìjẹ́wọ́ láti ṣe ìṣe yìí.','All custom labels have been reset successfully.'=>'Gbogbo àkọlé àdáni ti túnṣe ni aṣeyọrí.','Number of characters in Yoast SEO focus keyword'=>'Iye awọn ohun kikọ ninu ọrọ-ọrọ idojukọ Yoast SEO','Minimum of %d character in Yoast SEO focus keyword'=>'Kéré jùlọ ti %d àwòrán nínú ọrọ pataki Yoast SEO','Minimum of %d characters in Yoast SEO focus keyword'=>'Kere ju %d awọn ohun kikọ ninu ọrọ-ọrọ idojukọ Yoast SEO','Maximum of %d character in Yoast SEO focus keyword'=>'Max ti %d lẹta ninu Yoast SEO focus keyword','Maximum of %d characters in Yoast SEO focus keyword'=>'Maximu ti %d àwòrán nínú ọrọ pataki Yoast SEO','%d character in Yoast SEO focus keyword'=>'%d ohun kikọ ninu ọrọ-ọrọ idojukọ Yoast SEO','%d characters in Yoast SEO focus keyword'=>'%d awọn ohun kikọ ninu ọrọ-ọrọ idojukọ Yoast SEO','Between %d and %d characters in Yoast SEO focus keyword'=>'Laarin %d ati %d awọn kikọ ni ọrọ-ọrọ idojuko Yoast SEO','Number of characters in Yoast SEO meta description'=>'Iye awọn ohun kikọ ninu apejuwe meta Yoast SEO','Minimum of %d character in Yoast SEO meta description'=>'Kere ju %d ohun kikọ ninu apejuwe meta Yoast SEO','Minimum of %d characters in Yoast SEO meta description'=>'Kere ju %d awọn ohun kikọ ninu apejuwe meta Yoast SEO','Maximum of %d character in Yoast SEO meta description'=>'Max ti %d lẹta ninu Yoast SEO meta description','Maximum of %d characters in Yoast SEO meta description'=>'Maximu ti %d àwòrán nínú ìtàn meta Yoast SEO','%d character in Yoast SEO meta description'=>'%d ohu